// Rollup config for the one-shot CodeMirror 6 bundle.
// Output is an IIFE assigned to `window.CM`.
import { nodeResolve } from "@rollup/plugin-node-resolve";
import terser from "@rollup/plugin-terser";

export default {
  input: "entry.mjs",
  output: {
    file: "../vendor/codemirror.min.js",
    format: "iife",
    name: "CM",
    extend: false,
    // Header so anyone reading the vendored file knows where it came from.
    banner:
      "/* grug-brain CodeMirror 6 bundle — generated by web/build/. " +
      "Do not edit; regenerate via `cd web/build && npm ci && npm run bundle`. */",
  },
  plugins: [nodeResolve(), terser()],
};
